mapper.select:
SELECT c.id, c.name, c.grade, c.year, (SELECT COUNT(1) FROM student s WHERE s.class_id = c.id AND s.deleted = 0) AS studentCount FROM `class` c WHERE c.deleted = 0
AND c.year = #{year}
ORDER BY c.id DESC

SELECT COUNT(1) FROM `class`
WHERE name = #{name} AND year = #{year} AND deleted = 0

    AND id != #{excludeId}
